INSERT INTO "Post" ("id", "title", "slug", "content", "thumbnail", "isPublished", "createdAt", "updatedAt") VALUES
('cmllwbpyw002xgwdt8in2nwbl', 'Hướng dẫn chọn gạch ốp lát cho ngôi nhà hiện đại', 'huong-dan-chon-gach-op-lat', '<h2>Các loại gạch phổ biến</h2><p>Gạch vân đá Marble, vân đá tự nhiên, vân gỗ — mỗi loại phù hợp cho không gian khác nhau.</p>', 'https://tygjmrhandbffjllxveu.supabase.co/storage/v1/object/public/images/posts/1771145180782-wg39oi.jpg', TRUE, '2026-02-14T05:48:43.448Z', '2026-02-15T08:46:24.069Z'),
('cmllwbpqv002wgwdtw5ibot2y', 'Xu hướng thiết kế nhà bếp hiện đại 2024', 'xu-huong-thiet-ke-nha-bep-hien-dai-2024', '<h2>Phong cách tối giản</h2><p>Xu hướng nhà bếp 2024 thiên về phong cách tối giản với tông màu trắng, xám.</p>', 'https://tygjmrhandbffjllxveu.supabase.co/storage/v1/object/public/images/posts/1771145197187-tsv41w.jpg', TRUE, '2026-02-14T05:48:43.160Z', '2026-02-15T08:46:39.923Z'),
('cmllwbpj4002vgwdtvot37ikn', 'Cách chọn thiết bị vệ sinh phù hợp cho gia đình', 'cach-chon-thiet-bi-ve-sinh-phu-hop', '<h2>1. Xác định ngân sách</h2><p>Trước khi mua thiết bị vệ sinh, bạn cần xác định ngân sách phù hợp.</p><h2>2. Chọn thương hiệu uy tín</h2><p>Nên chọn các thương hiệu có bảo hành chính hãng tại Việt Nam.</p>', 'https://tygjmrhandbffjllxveu.supabase.co/storage/v1/object/public/images/posts/1771145213635-flmk4.jpg', TRUE, '2026-02-14T05:48:42.881Z', '2026-02-15T08:46:56.261Z');
